import * as React from "react"

import { StaticImage } from "gatsby-plugin-image"
import Tooltip from "../tooltip/tooltip"
import * as styles from "./tag_filter.module.css"

const filterImage = {
  "garden": (
    <StaticImage
      src="../../images/filter-garden.png"
      alt="С градина"
      imgStyle={{objectFit: 'contain'}}
      width={45}
      height={82}
      quality={95}
      formats={["AUTO", "WEBP", "AVIF"]}
    />
  ),
  "moonshine": (
    <StaticImage
      src="../../images/filter-moonshine.png"
      alt="Домашен алкохол"
      imgStyle={{objectFit: 'contain'}}
      width={45}
      height={82}
      quality={95}
      formats={["AUTO", "WEBP", "AVIF"]}
    />
  ),
  "non-stop": (
    <StaticImage
      src="../../images/filter-non-stop.png"
      alt="Работи до късно"
      imgStyle={{objectFit: 'contain'}}
      width={45}
      height={82}
      quality={95}
      formats={["AUTO", "WEBP", "AVIF"]}
    />
  ),
  "vegan": (
    <StaticImage
      src="../../images/filter-vegan.png"
      alt="Вегански ястия"
      imgStyle={{objectFit: 'contain'}}
      width={45}
      height={82}
      quality={95}
      formats={["AUTO", "WEBP", "AVIF"]}
    />
  ),
  "smoking": (
    <StaticImage
      src="../../images/filter-smoking.png"
      alt="Пуши се"
      imgStyle={{objectFit: 'contain'}}
      width={45}
      height={82}
      quality={95}
      formats={["AUTO", "WEBP", "AVIF"]}
    />
  ),
}

const TagFilter = ({ currentFilter, tag, updateFilter }) => {
  return (
    <Tooltip text={tag.Name}>
      <button onClick={() => updateFilter(tag.Slug)} className={currentFilter != tag.Slug ? styles.grayscale : ''}>
        {filterImage[tag.Slug]}
      </button>
    </Tooltip>
  )
}

export default TagFilter
